from flask import Flask, request, jsonify
import requests
app = Flask(__name__)
# Assuming you have already set up Elasticsearch and configured it correctly in your application 
elastic_url='http://localhost:9200/products/_search?q={}&format=json'.replace('@', '') # replace with actual elastic url. For local testing, use http://127.0.0.1:9200 in place of localhost
# ElasticSearch client setup – for python requests library is used to interact and perform HTTP request on the server side (Elasicsearch) using Python language as well .  
@app.route('/api/search', methods=['GET']) # Flask decorator that binds a function to /url route, method can be GET or POST 
def search():    
    query = request.args.get('q')     
    if not query:         
        return jsonify({"error": "Missing keyword parameter in the query string."}),400 # Bad Request status code is returned when no argument provided for 'q' key  
        
    try:# Try block to handle exceptions – Elasticsearch might throw an exception.     
       response = requests.get(elastic_url, params={'q':query})# Send a GET request with the keyword from query string and get back json data     # replace '@' in elastic url above by actual address of your server if it is not local  Elasticsearch  
    except Exception as e:     
       return jsonify({"error": "Error occurred while communicating to ElasticSearch. Please try again later."}),500# Internal Server Error status code returned when an exception occurs     # replace '@' in elastic url above by actual address of your server if it is not local  Elasticsearch  
       
    return jsonify(response.json()), response.status_code     
if __name__ == "__main__":        
 app.run()# Run the Flask application on localhost port:5001 by default, you can change this as per your requirements  # replace '@' in elastic url above by actual address of your server if it is not local Elasticsearch